-- CONEXA - Seed CEPI Pelicano
-- Gerado a partir das planilhas XLSX anexadas.
-- Idempotente: pode ser executado mais de uma vez sem duplicar registros principais.
-- Senha padrão dos profissionais: usa a senha hash existente de professor@testepiloto.com.br/coordenador@testepiloto.com.br/secretaria@testepiloto.com.br.
BEGIN;
DO $$
DECLARE
  v_mantenedora_id TEXT;
  v_unit_id TEXT := 'seed_unit_pelicano';
  v_password TEXT;
  v_role_professor TEXT;
  v_role_unidade_administrativo TEXT;
  v_role_unidade_coordenador_pedagogico TEXT;
  v_role_unidade_diretor TEXT;
  v_role_unidade_nutricionista TEXT;
BEGIN
  SELECT id INTO v_mantenedora_id FROM "Mantenedora" WHERE "isActive" = TRUE ORDER BY "createdAt" ASC LIMIT 1;
  IF v_mantenedora_id IS NULL THEN RAISE EXCEPTION 'Nenhuma mantenedora ativa encontrada.'; END IF;
  SELECT password INTO v_password FROM "User" WHERE email IN ('professor@testepiloto.com.br','coordenador@testepiloto.com.br','secretaria@testepiloto.com.br') ORDER BY email LIMIT 1;
  IF v_password IS NULL THEN RAISE EXCEPTION 'Não foi possível localizar senha modelo dos usuários de teste.'; END IF;

  INSERT INTO "Unit" (id,"mantenedoraId",name,code,address,city,state,"zipCode",email,phone,capacity,"ageGroupsServed","isActive","createdAt","updatedAt")
  VALUES (v_unit_id, v_mantenedora_id, 'CEPI Pelicano', 'PELICANO', NULL, 'Brasília', 'DF', NULL, NULL, NULL, 400, '0-5', TRUE, NOW(), NOW())
  ON CONFLICT ("mantenedoraId", code) DO UPDATE SET name=EXCLUDED.name, capacity=EXCLUDED.capacity, "ageGroupsServed"=EXCLUDED."ageGroupsServed", "isActive"=TRUE, "updatedAt"=NOW() RETURNING id INTO v_unit_id;

  INSERT INTO "Role" (id,"mantenedoraId",name,description,level,type,"isActive","isCustom","createdAt","updatedAt")
  VALUES ('seed_role_' || lower('PROFESSOR') || '_' || v_mantenedora_id, v_mantenedora_id, 'Professor(a)', 'Criado/garantido pelo seed Pelicano', 'PROFESSOR'::"RoleLevel", 'PROFESSOR'::"RoleType", TRUE, FALSE, NOW(), NOW())
  ON CONFLICT ("mantenedoraId", type) DO UPDATE SET name=EXCLUDED.name, "isActive"=TRUE, "updatedAt"=NOW() RETURNING id INTO v_role_professor;
  INSERT INTO "Role" (id,"mantenedoraId",name,description,level,type,"isActive","isCustom","createdAt","updatedAt")
  VALUES ('seed_role_' || lower('UNIDADE_ADMINISTRATIVO') || '_' || v_mantenedora_id, v_mantenedora_id, 'Secretaria / Administrativo da Unidade', 'Criado/garantido pelo seed Pelicano', 'UNIDADE'::"RoleLevel", 'UNIDADE_ADMINISTRATIVO'::"RoleType", TRUE, FALSE, NOW(), NOW())
  ON CONFLICT ("mantenedoraId", type) DO UPDATE SET name=EXCLUDED.name, "isActive"=TRUE, "updatedAt"=NOW() RETURNING id INTO v_role_unidade_administrativo;
  INSERT INTO "Role" (id,"mantenedoraId",name,description,level,type,"isActive","isCustom","createdAt","updatedAt")
  VALUES ('seed_role_' || lower('UNIDADE_COORDENADOR_PEDAGOGICO') || '_' || v_mantenedora_id, v_mantenedora_id, 'Coordenação Pedagógica da Unidade', 'Criado/garantido pelo seed Pelicano', 'UNIDADE'::"RoleLevel", 'UNIDADE_COORDENADOR_PEDAGOGICO'::"RoleType", TRUE, FALSE, NOW(), NOW())
  ON CONFLICT ("mantenedoraId", type) DO UPDATE SET name=EXCLUDED.name, "isActive"=TRUE, "updatedAt"=NOW() RETURNING id INTO v_role_unidade_coordenador_pedagogico;
  INSERT INTO "Role" (id,"mantenedoraId",name,description,level,type,"isActive","isCustom","createdAt","updatedAt")
  VALUES ('seed_role_' || lower('UNIDADE_DIRETOR') || '_' || v_mantenedora_id, v_mantenedora_id, 'Diretor(a) de Unidade', 'Criado/garantido pelo seed Pelicano', 'UNIDADE'::"RoleLevel", 'UNIDADE_DIRETOR'::"RoleType", TRUE, FALSE, NOW(), NOW())
  ON CONFLICT ("mantenedoraId", type) DO UPDATE SET name=EXCLUDED.name, "isActive"=TRUE, "updatedAt"=NOW() RETURNING id INTO v_role_unidade_diretor;
  INSERT INTO "Role" (id,"mantenedoraId",name,description,level,type,"isActive","isCustom","createdAt","updatedAt")
  VALUES ('seed_role_' || lower('UNIDADE_NUTRICIONISTA') || '_' || v_mantenedora_id, v_mantenedora_id, 'Nutricionista da Unidade', 'Criado/garantido pelo seed Pelicano', 'UNIDADE'::"RoleLevel", 'UNIDADE_NUTRICIONISTA'::"RoleType", TRUE, FALSE, NOW(), NOW())
  ON CONFLICT ("mantenedoraId", type) DO UPDATE SET name=EXCLUDED.name, "isActive"=TRUE, "updatedAt"=NOW() RETURNING id INTO v_role_unidade_nutricionista;

