SELECT c.name AS turma, COUNT(e.id) AS matriculas FROM "Classroom" c LEFT JOIN "Enrollment" e ON e."classroomId"=c.id AND e.status='ATIVA' WHERE c."unitId"=(SELECT id FROM "Unit" WHERE code='PELICANO' LIMIT 1) GROUP BY c.name ORDER BY c.name;